var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在你腦海中的那個機械……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"不，是那個孩子，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して彼女を呼び出すと、約束の場所で待っているとの返事が返ってきた。","ENG":"Having decided that, you called her. She answered she'd be waiting for you at the place you promised to meet.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"……오셨군요, 달링.","JPN":"……いらっしゃい、ダーリン。","ENG":"...You've come, darling.","TWN":"……你來啦，親愛的。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"후후, 안심하세요. 이곳에는 저희 둘 뿐이랍니다.","JPN":"ふふ、ご安心を。ここには私たち2人しかいません。","ENG":"Haha, don't worry. There's no one else here but the two of us.","TWN":"呵呵，別擔心，這裡只有我們兩個人而已。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"아쉽게도 저희의 결혼을 축하할 하객은 없는 모양이니까요.","JPN":"残念ながら、私たちの結婚をお祝いしてくれる招待客はいないようですから。","ENG":"Sadly, it seems no guests came to celebrate our wedding.","TWN":"很遺憾，似乎沒有任何賓客來恭喜我們結婚。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"모든 반대를 무릅쓰고, 모두에게 미움받으면서까지… 결국 저를 선택하다니…….","JPN":"すべての反対を押し切って、皆に嫌われてまで……私を選ぶなんて……","ENG":"You chose me despite all the opposition... even though it meant being hated by everyone...","TWN":"就算面對眾人的反對，甚至被所有人討厭…你還是要選擇我……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"정말이지, 당신은 참 이상한 사람이에요.","JPN":"本当に、あなたは変な人ですね。","ENG":"Truly, you're a strange one.","TWN":"你真是個怪人呢。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"물론, 그런 알 수 없는 점이 당신의 매력이지만…….","JPN":"もちろん、そういうわけのわからないところがあなたの魅力ではありますが……","ENG":"But that's part of your charm...","TWN":"不過，也正因為你令人無法捉摸，才顯得迷人……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"모든 것은 각본대로…….","JPN":"すべては脚本どおりに……","ENG":"Everything according to the script...","TWN":"一切都要照著劇本走……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"그건 무척이나 오랜 다짐이랍니다.","JPN":"それは遠い昔に決めた覚悟でした。","ENG":"That is my old determination.","TWN":"這是我長久以來的堅持。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"그 각본에서 어떤 배역을 맡게 되더라도, 그 끝에 어떤 결말이 기다리고 있더라도…….","JPN":"その脚本でどのような役を担当することになろうとも、その先にどんな結末が待っていようとも……","ENG":"No matter what role I played in the script, no matter what ending awaits...","TWN":"無論在劇本中扮演什麼角色，最後會迎來什麼樣的結局……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"기꺼이 모든 것을 받아들이겠다는 선택이었죠.","JPN":"喜んですべてを受け入れようという選択でした。","ENG":"It was a choice to accept it all, no matter what.","TWN":"我都決定要欣然接受一切。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"하지만 역시 당신 앞에 서니, 그 각오마저 흔들리더군요.","JPN":"ですが、やはりあなたのそばに立つと、その覚悟も揺さぶられてしまった。","ENG":"But standing before you like this, I found even that determination beginning to waver.","TWN":"但是，當我站在你面前，這份決心果然也開始動搖。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"당신의 따뜻한 손이, 두근거리는 심장 소리… 그리고 그 감미로운 프로포즈가…….","JPN":"あなたの暖かい手が、鼓動を打つ心臓の音が……そして、その甘いプロポーズが……","ENG":"Your warm touch, the sound of your heartbeat... and that sweet, heartfelt proposal...","TWN":"你溫暖的手、心跳聲…還有令人心醉的求婚……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"결국에는 제가 짊어지고 있던 것을 전부 내려놓게 만들었답니다.","JPN":"とうとう私を、背負っていたものすべてから解放してしまったのです。","ENG":"In the end, they made me lay down everything I had been carrying for so long.","TWN":"使我放下肩上一切的重擔。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"그러니 이제 우리 두 사람의 관계는 반드시 정해진 각본대로일 필요는 없겠죠.","JPN":"ですから、もう私たち2人の関係は必ずしも決められた脚本どおりである必要はありません。","ENG":"So maybe our relationship doesn't have to follow the script anymore.","TWN":"既然如此，我們之間的關係，也無須再拘泥於制式的劇本。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"물론, 그렇다고 지금껏 제가 저지른 모든 것이 없었던 일이 되는 건 아니겠지만…….","JPN":"もちろん、そうはいっても今まで私がやってきたすべてがなかったことになるわけではありませんが……","ENG":"Of course, that doesn't mean everything I've done until now can be erased...","TWN":"當然，這並不代表我做過的事就能一筆勾銷……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"제 진심을 알아봐 준 당신과 함께라면, 저는 무엇이든 할 수 있어요.","JPN":"私の本当の気持ちに気づいてくれたあなたと一緒なら、私は何でもできます。","ENG":"But with you, the one who saw through to my heart, I feel like I can do anything.","TWN":"但只要和能明白我真心的你在一起，我什麼都做得到。"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"그게 무엇이든, 저는…….","JPN":"それが何であろうと、私は……","ENG":"Whatever it is, I...","TWN":"無論什麼事，我……"},"stage":{"bg":"CHURCH2","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"때마침 웨딩마치가 울리네요.","JPN":"ちょうどウェディングマーチが鳴り始めましたね。","ENG":"Oh, the wedding march has begun.","TWN":"正好，響起結婚進行曲響呢。"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"후후, 저는 이렇게 가슴이 두근거리는데… 역시 당신은 이런 상황에서도 표정이 여유롭네요.","JPN":"ふふ、私はこんなにもドキドキしているのに……やはりあなたという人は、このような状況でも余裕がありますね。","ENG":"Haha, my heart's pounding... But you're as composed as ever.","TWN":"呵呵，我心跳得那麼厲害…而你在這種情況下還是那麼從容。"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"어쩌면 당신은 처음부터 이렇게 될 줄 알고 있었던 걸까요?","JPN":"もしかしたら、あなたは最初からこうなるとわかっていたのでしょうか？","ENG":"Or maybe you knew it'd be like this all along?","TWN":"或許你從一開始，就知道會走到這一步對吧？"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"자, 그러니 우리 두 사람만의 결혼식을 진행하도록 하죠.","JPN":"では、私たち2人だけの結婚式を始めましょう。","ENG":"Now then, let's begin our own special wedding. Just the two of us.","TWN":"那就開始只屬於我們兩個人的婚禮吧。"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"이제는 당신의 팬이 아닌, 당신의 반려로서 맹세합니다.","JPN":"もうあなたのファンではなく、あなたの伴侶として誓います。","ENG":"From this moment on, I vow not as your fan, but as your partner.","TWN":"現在起，我不再是你的粉絲，我以你伴侶的身分發誓。"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"저는 당신을 포기하지 않을 거예요. 어떤 일이 있더라도 마주잡은 손을 놓지 않을 거예요.","JPN":"私はあなたを諦めません。どんなことがあっても、繋いだ手を離しません。","ENG":"I'll never give up on you. No matter what happens, I'll never let go of your hand.","TWN":"我絕對不會拋下你。無論發生什麼事，我都不會鬆開這隻握緊的手。"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"그러니까 당신도 맹세해주시겠어요, 달링?","JPN":"だから、あなたも誓ってください、ダーリン。","ENG":"So will you make a vow too, darling?","TWN":"你也可以發誓嗎，親愛的？"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"앞으로도 쭉 제 곁에 있겠다고…….","JPN":"これからもずっと私のそばにいると……","ENG":"Promise me you'll stay by my side...","TWN":"以後也會一直待在我身邊……"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_SPECIAL","text":{"KOREA":"마지막까지… 이 손을 놓지 않겠다고…….","JPN":"最後まで……この手を離さないと……","ENG":"That you'll never let go... not even at the very end...","TWN":"直到最後…都不會鬆開我的手……"},"stage":{"bg":"CHURCH2","bgm":"SKIN_SIXWING_CA_ACTOR_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};